package testutil

import (
	"os"
	"path/filepath"
	"testing"
)

// GetFixturesDir returns the path to the test fixtures directory
func GetFixturesDir() string {
	// Get the current working directory
	wd, err := os.Getwd()
	if err != nil {
		return "../../tests/fixtures"
	}

	// Navigate up to the project root and then to fixtures
	root := filepath.Dir(filepath.Dir(wd))
	return filepath.Join(root, "tests", "fixtures")
}

// LoadFixture loads a fixture file from the tests/fixtures directory
func LoadFixture(t *testing.T, filename string) string {
	t.Helper()

	fixturesDir := GetFixturesDir()
	path := filepath.Join(fixturesDir, filename)

	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("Failed to load fixture %s: %v", filename, err)
	}

	return string(data)
}

// CreateTempFile creates a temporary file with the given content
func CreateTempFile(t *testing.T, content string) string {
	t.Helper()

	tmpfile, err := os.CreateTemp("", "meta-cc-test-*.jsonl")
	if err != nil {
		t.Fatalf("Failed to create temp file: %v", err)
	}

	if _, err := tmpfile.Write([]byte(content)); err != nil {
		t.Fatalf("Failed to write to temp file: %v", err)
	}

	if err := tmpfile.Close(); err != nil {
		t.Fatalf("Failed to close temp file: %v", err)
	}

	return tmpfile.Name()
}

