// TestQueryCommandExists tests that the query command is registered
func TestQueryCommandExists(t *testing.T) {
	// Find query command in root's children
	found := false
	for _, cmd := range rootCmd.Commands() {
		if cmd.Name() == "query" {
			found = true
			break
		}
	}

	if !found {
		t.Error("query command not found in root command")
	}
}

// TestQueryCommandHelp tests that help text displays properly
func TestQueryCommandHelp(t *testing.T) {
	// Find query command
	var queryCommand *cobra.Command
	for _, cmd := range rootCmd.Commands() {
		if cmd.Name() == "query" {
			queryCommand = cmd
			break
		}
	}

	if queryCommand == nil {
		t.Fatal("query command not found")
	}

	// Check that help text mentions subcommands
	help := queryCommand.Long
	if help == "" {
		t.Error("query command has no long description")
	}
}

// TestQueryPersistentFlags tests that common query flags are available
func TestQueryPersistentFlags(t *testing.T) {
	// Find query command
	var queryCommand *cobra.Command
	for _, cmd := range rootCmd.Commands() {
		if cmd.Name() == "query" {
			queryCommand = cmd
			break
		}
	}

	if queryCommand == nil {
		t.Fatal("query command not found")
	}

	// Check persistent flags
	flags := []string{"limit", "sort-by", "reverse"}
	for _, flagName := range flags {
		flag := queryCommand.PersistentFlags().Lookup(flagName)
		if flag == nil {
			t.Errorf("persistent flag --%s not found", flagName)
		}
	}
}

