func initConfig() {
	viper.AutomaticEnv()
}

// getSessionFiles returns session files based on scope flag
// Priority: explicit --scope flag > default (project)
func getSessionFiles() ([]string, error) {
	loc := locator.NewSessionLocator()

	// Determine project path
	projPath := projectPath
	if projPath == "" {
		cwd, err := os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get current directory: %w", err)
		}
		projPath = cwd
	}

	// Validate scope
	if scopeFlag != ScopeProject && scopeFlag != ScopeSession {
		return nil, fmt.Errorf("invalid scope: %s (must be 'project' or 'session')", scopeFlag)
	}

	// Handle scope
	if scopeFlag == ScopeSession {
		// Legacy behavior: single session
		file, err := loc.Locate(locator.LocateOptions{
			SessionID:   sessionID,
			ProjectPath: projPath,
		})
		if err != nil {
			return nil, err
		}
		return []string{file}, nil
	}

	// Default: project scope (all sessions)
	return loc.LocateProject(projPath)
}

// getEffectiveLimit returns the limit to use based on command context
// Priority: explicit --limit flag > $META_CC_DEFAULT_LIMIT > command-specific default > 0
func getEffectiveLimit(commandType string) int {
	// Priority 1: User explicitly set --limit flag (highest priority)
	if rootCmd.PersistentFlags().Changed("limit") {
		return limitFlag
	}

	// Priority 2: Environment variable override
	if envLimit := os.Getenv("META_CC_DEFAULT_LIMIT"); envLimit != "" {
		if parsed, err := strconv.Atoi(envLimit); err == nil && parsed >= 0 {
			return parsed
		}
		// Invalid env var value, fall through to smart defaults
		fmt.Fprintf(os.Stderr, "Warning: Invalid META_CC_DEFAULT_LIMIT=%s, using smart default\n", envLimit)
	}

	// Priority 3: Command-specific smart defaults
	switch commandType {
	case "stats", "aggregate":
