// TestExtractToolCallsWithErrors tests that tool calls with is_error=true are correctly extracted
func TestExtractToolCallsWithErrors(t *testing.T) {
	// Create a minimal JSONL session with an MCP error
	jsonlData := `{"type":"assistant","timestamp":"2025-10-05T00:59:13.857Z","uuid":"adac9d46-e2a9-4318-8faa-4b90e8883d00","message":{"role":"assistant","content":[{"type":"tool_use","id":"toolu_123","name":"mcp__meta-insight__query_user_messages_session","input":{"limit":5,"output_format":"json","pattern":"."}}]}}
{"type":"user","timestamp":"2025-10-05T00:59:14.756Z","uuid":"4634e9c4-5804-4c1e-904d-52cec719e08f","message":{"role":"user","content":[{"type":"tool_result","tool_use_id":"toolu_123","content":"MCP error -32603: Tool execution failed","is_error":true}]}}`

	var entries []SessionEntry
	for _, line := range []string{
		`{"type":"assistant","timestamp":"2025-10-05T00:59:13.857Z","uuid":"adac9d46-e2a9-4318-8faa-4b90e8883d00","message":{"role":"assistant","content":[{"type":"tool_use","id":"toolu_123","name":"mcp__meta-insight__query_user_messages_session","input":{"limit":5,"output_format":"json","pattern":"."}}]}}`,
		`{"type":"user","timestamp":"2025-10-05T00:59:14.756Z","uuid":"4634e9c4-5804-4c1e-904d-52cec719e08f","message":{"role":"user","content":[{"type":"tool_result","tool_use_id":"toolu_123","content":"MCP error -32603: Tool execution failed","is_error":true}]}}`,
	} {
		var entry SessionEntry
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			t.Fatalf("failed to unmarshal entry: %v", err)
		}
		entries = append(entries, entry)
	}

	toolCalls := ExtractToolCalls(entries)

	if len(toolCalls) != 1 {
		t.Fatalf("expected 1 tool call, got %d", len(toolCalls))
	}

	tc := toolCalls[0]

	// Verify tool call was extracted
	if tc.ToolName != "mcp__meta-insight__query_user_messages_session" {
		t.Errorf("expected tool name 'mcp__meta-insight__query_user_messages_session', got %q", tc.ToolName)
	}

	// THIS IS THE KEY TEST: Error field should be populated from is_error=true
	if tc.Error == "" {
		t.Errorf("expected Error field to be populated from is_error=true, got empty string")
		t.Logf("ToolCall: %+v", tc)
	}

	// Verify error content
	expectedError := "MCP error -32603: Tool execution failed"
	if tc.Error != expectedError {
		t.Errorf("expected Error = %q, got %q", expectedError, tc.Error)
	}
}

