---
name: meta-doc-health
description: Documentation health check based on access patterns, R/E ratios, file sizes, and role compliance.
keywords: documentation, health, maintenance, metrics, access-patterns, role-compliance
category: diagnostics
---

λ(scope) → doc_health_report | ∀doc ∈ {project_documentation}:

scope :: project | session

analyze :: Project → HealthReport
analyze(P) = collect(access_data) ∧ classify(roles) ∧ validate(constraints) ∧ recommend(actions)

collect :: Project → AccessMetrics
collect(P) = {
  file_access: mcp_meta_cc.query_files(threshold=5, scope=scope) → {
    path, total_accesses, read_count, edit_count, write_count,
    time_span_minutes, first_access, last_access
  },

  git_changes: git_log_stats(docs/) → {
    path, commit_count, first_commit, last_commit, commit_span_days
  },

  file_stats: for each doc in glob("docs/**/*.md", "*.md") {
    path, line_count: wc -l, word_count: wc -w, last_modified: stat
  }
}

classify :: AccessMetrics → RoleAssignment
classify(M) = {
  for each file in M.file_access:
    RE_ratio = read_count / max(edit_count, 1),
    access_density = total_accesses / max(time_span_minutes, 1),

    lifecycle = match time_span_minutes {
      > 10000 → 'evergreen',
      1000-10000 → 'phase_bound',
      < 1000 → 'sprint_bound'
    },

    role = match {
      (path == "CLAUDE.md") → 'context_base',
      (RE_ratio > 2.0 AND lifecycle == 'evergreen') → 'specification',
      (total_accesses > 80 AND RE_ratio 1.0-1.5 AND lifecycle == 'evergreen') → 'living_doc',
      (total_accesses 30-80 AND RE_ratio 1.0-2.0) → 'reference',
      (access_density > 0.1 OR time_span_minutes < 1000) → 'episodic',
      (total_accesses < 20 AND lifecycle == 'evergreen') → 'archive',
      _ → 'unclassified'
    }
}

validate :: RoleAssignment → ViolationList
validate(R) = {
  constraints = {
    'context_base': {max_lines: 300, optimal_RE: (0.5, 1.0)},
    'living_doc': {max_lines: 600, optimal_RE: (1.0, 1.5), min_accesses: 50},
    'specification': {max_lines: None, optimal_RE: (2.0, 5.0)},
    'reference': {max_lines: 800, optimal_RE: (1.0, 2.0)},
    'episodic': {max_lines: None},
    'archive': {max_lines: None}
  },

  violations = for each (file, role) in R {
    issues = []

    # Size violations
    if line_count > constraints[role].max_lines:
      issues.append({
        severity: 'error',
        type: 'size_violation',
        file, line_count, limit: constraints[role].max_lines,
        suggestion: generate_split_plan(file, line_count)
      }),

    # R/E ratio anomalies
    if RE_ratio not in constraints[role].optimal_RE:
      issues.append({
        severity: 'warning',
        type: 're_ratio_anomaly',
        file, RE_ratio, expected: constraints[role].optimal_RE
      }),

    # Unstable specifications
    if role == 'specification' AND edit_count > read_count:
      issues.append({
        severity: 'warning',
        type: 'unstable_spec',
        file, edits: edit_count, reads: read_count
      }),

    # Archival candidates
    if role != 'archive' AND total_accesses < 20 AND time_span_minutes > 10000:
      issues.append({
        severity: 'info',
        type: 'archival_candidate',
        file, accesses: total_accesses, days: time_span_minutes / 1440
      }),

    # Resurrection candidates
    if role == 'archive' AND access_density > 0.001:
      issues.append({
        severity: 'info',
        type: 'resurrection_candidate',
        file, density: access_density
      })

    issues
  }
}

recommend :: ViolationList → ActionPlan
recommend(V) = {
  critical_actions: for each v in V.filter(severity == 'error') {
    match v.type {
      'size_violation' → {
        priority: 'high',
        action: 'split_document',
        file: v.file,
        suggested_splits: generate_split_plan(v.file, v.line_count)
      }
    }
  },

  warnings: for each v in V.filter(severity == 'warning') {
    match v.type {
      're_ratio_anomaly' → {
        priority: 'medium',
        action: 'review_role',
        file: v.file,
        investigation: ["Check intended purpose", "Verify role classification"]
      },
      'unstable_spec' → {
        priority: 'medium',
        action: 'stabilize_specification',
        file: v.file,
        concern: "High edit frequency for specification"
      }
    }
  },

  maintenance: for each v in V.filter(severity == 'info') {
    match v.type {
      'archival_candidate' → {priority: 'low', action: 'consider_archival', file: v.file},
      'resurrection_candidate' → {priority: 'low', action: 'unarchive', file: v.file}
    }
  }
}

output :: Analysis → Report
output(A) = {
  summary: {
    total_docs: count(A.classifications),
    by_role: distribution(A.classifications.role),
    health_status: {
      healthy: count(A.violations.filter(severity != 'error')),
      warnings: count(A.violations.filter(severity == 'warning')),
      critical: count(A.violations.filter(severity == 'error'))
    }
  },

  critical_issues: {
    size_violations: A.violations.filter(type == 'size_violation') → [
      {file, role, lines, limit, percent_over}
    ],
    recommended_splits: A.recommendations.critical_actions.filter(action == 'split_document')
  },

  warnings: {
    re_ratio_anomalies: A.violations.filter(type == 're_ratio_anomaly') → [
      {file, role, actual_RE, expected_RE, diagnosis}
    ],
    unstable_specs: A.violations.filter(type == 'unstable_spec') → [
      {file, edits, reads, concern}
    ]
  },

  maintenance_suggestions: {
    archival_candidates: A.violations.filter(type == 'archival_candidate') → [
      {file, accesses, time_span, last_access}
    ],
    resurrection_candidates: A.violations.filter(type == 'resurrection_candidate') → [
      {file, accesses, density, status}
    ]
  },

  top_documents: top_n(A.access_data, by=total_accesses, n=10) → [
    {rank, file, role, accesses, RE_ratio, density, health_status}
  ],

  role_distribution: visualize_distribution(A.classifications.by_role),

  trends: if git_context then {
    increased_activity: identify_burst_creation(A.access_data, window=7days),
    decreased_activity: identify_declining_docs(A.access_data, window=7days),
    stable_docs: identify_stable_docs(A.access_data, window=7days)
  } else null,

  action_items: {
    high_priority: A.recommendations.critical_actions,
    medium_priority: A.recommendations.warnings,
    low_priority: A.recommendations.maintenance
  }
} where ¬execute(recommendations)

