// TestGetStringParam tests string parameter extraction
func TestGetStringParam(t *testing.T) {
	tests := []struct {
		name     string
		args     map[string]interface{}
		key      string
		defVal   string
		expected string
	}{
		{
			name:     "key exists",
			args:     map[string]interface{}{"scope": "session"},
			key:      "scope",
			defVal   "project",
			expected: "session",
		},
		{
			name:     "key missing - use default",
			args:     map[string]interface{}{},
			key:      "scope",
			defVal   "project",
			expected: "project",
		},
		{
			name:     "nil args - use default",
			args:     nil,
			key:      "scope",
			defVal   "project",
			expected: "project",
		},
		{
			name:     "non-string value - use default",
			args:     map[string]interface{}{"scope": 123},
			key:      "scope",
			defVal   "project",
			expected: "project",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := getStringParam(tt.args, tt.key, tt.defVal)
			if result != tt.expected {
				t.Errorf("expected %q, got %q", tt.expected, result)
			}
		})
	}
}

// TestGetBoolParam tests boolean parameter extraction
func TestGetBoolParam(t *testing.T) {
	tests := []struct {
		name     string
		args     map[string]interface{}
		key      string
		defVal   bool
		expected bool
	}{
		{
			name:     "key exists - true",
			args:     map[string]interface{}{"stats_only": true},
			key:      "stats_only",
			defVal:   false,
			expected: true,
		},
		{
			name:     "key exists - false",
			args:     map[string]interface{}{"stats_only": false},
			key:      "stats_only",
			defVal:   true,
			expected: false,
		},
		{
			name:     "key missing - use default",
			args:     map[string]interface{}{},
			key:      "stats_only",
			defVal:   true,
			expected: true,
		},
		{
			name:     "nil args - use default",
			args:     nil,
			key:      "stats_only",
			defVal:   false,
			expected: false,
		},
		{
			name:     "non-bool value - use default",
			args:     map[string]interface{}{"stats_only": "yes"},
			key:      "stats_only",
			defVal:   false,
			expected: false,
		},
	}

